CREATE TABLE IF NOT EXISTS "governor_roles" ("name" varchar not null, "description" varchar, "created_at" datetime, "updated_at" datetime, primary key ("name"));
CREATE TABLE IF NOT EXISTS "governor_groups" ("name" varchar not null, "created_at" datetime, "updated_at" datetime, primary key ("name"));
