CREATE TABLE IF NOT EXISTS "governor_ownerships" ("name" varchar not null, "created_at" datetime, "updated_at" datetime, primary key ("name"));
CREATE TABLE IF NOT EXISTS "governor_role_user" ("id" integer primary key autoincrement not null, "role_name" varchar not null, "user_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("role_name") references "governor_roles"("name") on delete CASCADE on update CASCADE, foreign key("user_id") references "users"("id") on delete CASCADE on update CASCADE);
