CREATE TABLE IF NOT EXISTS "governor_teamables" ("team_id" integer not null, "teamable_id" integer not null, "teamable_type" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "governor_teams"("id") on delete CASCADE on update CASCADE);
