CREATE INDEX "workflow_logs_stored_workflow_id_index" on "workflow_logs" ("stored_workflow_id");
CREATE TABLE IF NOT EXISTS "workflow_signals" ("id" integer primary key autoincrement not null, "stored_workflow_id" integer not null, "method" text not null, "arguments" text, "created_at" datetime, foreign key("stored_workflow_id") references "workflows"("id"));
