CREATE TABLE IF NOT EXISTS "workflow_exceptions" ("id" integer primary key autoincrement not null, "stored_workflow_id" integer not null, "class" text not null, "exception" text not null, "created_at" datetime, foreign key("stored_workflow_id") references "workflows"("id"));
CREATE INDEX "workflow_exceptions_stored_workflow_id_index" on "workflow_exceptions" ("stored_workflow_id");
