CREATE TABLE IF NOT EXISTS "organizations" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "settings" text, "owner_id" integer, "created_at" datetime, "updated_at" datetime, "created_by" integer, "updated_by" integer, "deleted_at" datetime, "deleted_by" integer, "billing_email" varchar, "tax_id" varchar, "billing_address" text, "stripe_customer_id" varchar, "paddle_customer_id" varchar, "extra_attributes" text, foreign key("owner_id") references "users"("id") on delete set null, foreign key("created_by") references "users"("id") on delete set null, foreign key("updated_by") references "users"("id") on delete set null, foreign key("deleted_by") references "users"("id") on delete set null);
CREATE INDEX "organizations_name_index" on "organizations" ("name");
CREATE UNIQUE INDEX "organizations_slug_unique" on "organizations" ("slug");
CREATE TABLE IF NOT EXISTS "organization_invitations" ("id" integer primary key autoincrement not null, "organization_id" integer not null, "email" varchar not null, "role" varchar not null default 'member', "status" varchar not null default 'pending', "token" varchar not null, "invited_by" integer not null, "expires_at" datetime not null, "accepted_at" datetime, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("organization_id") references "organizations"("id") on delete cascade, foreign key("invited_by") references "users"("id") on delete cascade);
