CREATE INDEX "organization_invitations_email_index" on "organization_invitations" ("email");
CREATE INDEX "organization_invitations_status_index" on "organization_invitations" ("status");
CREATE UNIQUE INDEX "organization_invitations_token_unique" on "organization_invitations" ("token");
CREATE TABLE IF NOT EXISTS "organization_user" ("organization_id" integer not null, "user_id" integer not null, "is_default" tinyint(1) not null default '0', "joined_at" datetime not null default CURRENT_TIMESTAMP, "invited_by" integer, "created_at" datetime, "updated_at" datetime, foreign key("organization_id") references "organizations"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, foreign key("invited_by") references "users"("id") on delete set null, primary key ("organization_id", "user_id"));
CREATE INDEX "organization_user_user_id_index" on "organization_user" ("user_id");
CREATE UNIQUE INDEX organization_user_unique_default ON organization_user(user_id) WHERE is_default = 1;
CREATE TABLE IF NOT EXISTS "posts" ("id" integer primary key autoincrement not null, "author_id" integer not null, "title" varchar not null, "slug" varchar not null, "excerpt" text, "content" text not null, "is_published" tinyint(1) not null default ('0'), "published_at" datetime, "meta_title" varchar, "meta_description" text, "meta_keywords" varchar, "views" integer not null default ('0'), "created_by" integer, "updated_by" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "organization_id" integer, foreign key("updated_by") references users("id") on delete set null on update no action, foreign key("created_by") references users("id") on delete set null on update no action, foreign key("author_id") references users("id") on delete cascade on update no action, foreign key("organization_id") references "organizations"("id") on delete set null);
CREATE INDEX "posts_is_published_index" on "posts" ("is_published");
CREATE INDEX "posts_published_at_index" on "posts" ("published_at");
CREATE INDEX "posts_slug_index" on "posts" ("slug");
CREATE UNIQUE INDEX "posts_slug_unique" on "posts" ("slug");
CREATE INDEX "posts_organization_id_index" on "posts" ("organization_id");
CREATE TABLE IF NOT EXISTS "help_articles" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "excerpt" text, "content" text not null, "category" varchar, "views" integer not null default ('0'), "helpful_count" integer not null default ('0'), "not_helpful_count" integer not null default ('0'), "order" integer not null default ('0'), "is_published" tinyint(1) not null default ('0'), "created_by" integer, "updated_by" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "organization_id" integer, foreign key("updated_by") references users("id") on delete set null on update no action, foreign key("created_by") references users("id") on delete set null on update no action, foreign key("organization_id") references "organizations"("id") on delete set null);
