CREATE INDEX "help_articles_organization_id_index" on "help_articles" ("organization_id");
CREATE TABLE IF NOT EXISTS "changelog_entries" ("id" integer primary key autoincrement not null, "title" varchar not null, "description" text not null, "version" varchar, "type" varchar not null default ('added'), "is_published" tinyint(1) not null default ('0'), "released_at" datetime, "created_by" integer, "updated_by" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "organization_id" integer, foreign key("updated_by") references users("id") on delete set null on update no action, foreign key("created_by") references users("id") on delete set null on update no action, foreign key("organization_id") references "organizations"("id") on delete set null);
CREATE INDEX "changelog_entries_is_published_index" on "changelog_entries" ("is_published");
CREATE INDEX "changelog_entries_released_at_index" on "changelog_entries" ("released_at");
