CREATE INDEX "changelog_entries_organization_id_index" on "changelog_entries" ("organization_id");
CREATE TABLE IF NOT EXISTS "contact_submissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "subject" varchar not null, "message" text not null, "status" varchar default ('new'), "created_at" datetime, "updated_at" datetime, "created_by" integer, "updated_by" integer, "organization_id" integer, foreign key("updated_by") references users("id") on delete set null on update no action, foreign key("created_by") references users("id") on delete set null on update no action, foreign key("organization_id") references "organizations"("id") on delete set null);
