CREATE TABLE IF NOT EXISTS "categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "type" varchar not null default ('default'), "_lft" integer not null default ('0'), "_rgt" integer not null default ('0'), "parent_id" integer, "created_at" datetime, "updated_at" datetime, "organization_id" integer, foreign key("organization_id") references "organizations"("id") on delete set null);
