CREATE TABLE IF NOT EXISTS "mail_attachments" ("id" integer primary key autoincrement not null, "mail_id" integer not null, "disk" varchar not null, "uuid" varchar not null, "filename" varchar not null, "mime" varchar not null, "inline" tinyint(1) not null, "size" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("mail_id") references "mails"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "mailables" ("id" integer primary key autoincrement not null, "mail_id" integer not null, "mailable_type" varchar not null, "mailable_id" integer not null, foreign key("mail_id") references "mails"("id") on delete cascade);
