CREATE TABLE IF NOT EXISTS "mails" ("id" integer primary key autoincrement not null, "uuid" varchar, "mail_class" varchar, "subject" varchar, "from" text, "reply_to" text, "to" text, "cc" text, "bcc" text, "html" text, "text" text, "opens" integer not null default ('0'), "clicks" integer not null default ('0'), "sent_at" datetime, "resent_at" datetime, "accepted_at" datetime, "delivered_at" datetime, "last_opened_at" datetime, "last_clicked_at" datetime, "complained_at" datetime, "soft_bounced_at" datetime, "hard_bounced_at" datetime, "unsubscribed_at" datetime, "created_at" datetime, "updated_at" datetime, "mailer" varchar not null, "stream_id" varchar, "tags" text, "transport" varchar);
CREATE INDEX "mails_mail_class_index" on "mails" ("mail_class");
CREATE INDEX "mails_uuid_index" on "mails" ("uuid");
CREATE TABLE IF NOT EXISTS "mail_events" ("id" integer primary key autoincrement not null, "mail_id" integer not null, "type" varchar not null, "ip_address" varchar, "hostname" varchar, "platform" varchar, "os" varchar, "browser" varchar, "user_agent" varchar, "city" varchar, "country_code" varchar, "link" text, "tag" varchar, "payload" text, "created_at" datetime, "updated_at" datetime, "occurred_at" datetime, "unsuppressed_at" datetime, foreign key("mail_id") references mails("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "announcements" ("id" integer primary key autoincrement not null, "title" varchar not null, "body" text not null, "level" varchar not null default ('info'), "scope" varchar not null default ('global'), "organization_id" integer, "starts_at" datetime, "ends_at" datetime, "is_active" tinyint(1) not null default ('1'), "created_by" integer, "created_at" datetime, "updated_at" datetime, "governor_owned_by" integer, "position" integer, foreign key("created_by") references users("id") on delete set null on update no action, foreign key("organization_id") references organizations("id") on delete set null on update no action, foreign key("governor_owned_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "webhook_calls" ("id" integer primary key autoincrement not null, "name" varchar not null, "url" varchar not null, "headers" text, "payload" text, "exception" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "health_check_result_history_items" ("id" integer primary key autoincrement not null, "check_name" varchar not null, "check_label" varchar not null, "status" varchar not null, "notification_message" text, "short_summary" varchar, "meta" text not null, "ended_at" datetime not null, "batch" varchar not null, "created_at" datetime, "updated_at" datetime);
